// ═══════════════════════════════════════════════════════════
// AI GATEWAY SERVICE
// Handles Personal Keys (localStorage) and Master Config (Firestore)
// Supports Google Gemini and Groq (OpenAI-compatible)
// ═══════════════════════════════════════════════════════════

import { getFirebaseApp } from '../firebase/config';
import { getFirestore, doc, getDoc } from 'firebase/firestore';

export interface AIProvider {
  name: 'groq' | 'gemini' | 'openai' | 'openrouter';
  endpoint: string;
  model: string;
  key?: string;
}

/**
 * Resolves the AI provider and API key to use.
 * Prioritizes local settings (Infinite Free Scale) before Master Config.
 */
export async function getAIProvider(): Promise<AIProvider> {
  // 1. Check LocalStorage for PERSONAL keys
  const personalGroqKey = typeof window !== 'undefined' ? localStorage.getItem('surveyos_personal_groq_key') : null;
  const personalGeminiKey = typeof window !== 'undefined' ? localStorage.getItem('surveyos_personal_gemini_key') : null;
  
  const personalGroqModel = (typeof window !== 'undefined' && localStorage.getItem('surveyos_personal_groq_model')) || "llama-3.1-70b-versatile";
  const personalGeminiModel = (typeof window !== 'undefined' && localStorage.getItem('surveyos_personal_gemini_model')) || "gemini-1.5-flash";

  if (personalGroqKey) {
    return {
      name: 'groq',
      endpoint: 'https://api.groq.com/openai/v1/chat/completions',
      model: personalGroqModel,
      key: personalGroqKey
    };
  }

  if (personalGeminiKey) {
    return {
      name: 'gemini',
      endpoint: `https://generativelanguage.googleapis.com/v1beta/models/${personalGeminiModel}:generateContent`,
      model: personalGeminiModel,
      key: personalGeminiKey
    };
  }

  // 2. Fallback to Master Config from Firestore
  try {
    const db = getFirestore(getFirebaseApp());
    const configDoc = await getDoc(doc(db, "ai_config", "routing"));
    
    if (configDoc.exists()) {
      const data = configDoc.data();
      const masterProvider = (data.providers || []).find((p: any) => p.enabled);
      if (masterProvider) {
        return {
          ...masterProvider,
          key: masterProvider.keys?.[0]
        };
      }
    }
  } catch (err) {
    console.warn('[AI Service] Master config unreachable:', err);
  }

  throw new Error("No AI provider configured. Please add your personal API keys in settings.");
}

/**
 * Direct browser-side call to the AI provider
 */
export async function callAIGateway(prompt: string, images: string[] = []): Promise<string> {
  const provider = await getAIProvider();
  
  if (!provider.key) throw new Error(`No API key found for ${provider.name}`);

  if (provider.name === 'gemini') {
    const url = `${provider.endpoint}?key=${provider.key}`;
    const parts: any[] = images.map(img => ({
      inlineData: {
        mimeType: "image/jpeg",
        data: img
      }
    }));
    parts.push({ text: prompt });

    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{ parts }],
        generationConfig: {
          temperature: 0.1,
          topP: 0.95,
          topK: 40,
          maxOutputTokens: 8192,
        }
      })
    });

    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(`Gemini API Error: ${err.error?.message || res.status}`);
    }

    const data = await res.json();
    const text = data.candidates?.[0]?.content?.parts?.[0]?.text || "";
    return text.replace(/```json|```/g, '').trim();
  } 
  
  // Groq / OpenAI compatible
  const messages: any[] = [];
  if (images.length > 0) {
    const content: any[] = images.map(img => ({
      type: "image_url",
      image_url: { url: `data:image/jpeg;base64,${img}` }
    }));
    content.push({ type: "text", text: prompt });
    messages.push({ role: "user", content });
  } else {
    messages.push({ role: "user", content: prompt });
  }

  const res = await fetch(provider.endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${provider.key}`
    },
    body: JSON.stringify({
      model: provider.model,
      messages,
      temperature: 0.1,
      response_format: { type: "json_object" }
    })
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(`${provider.name} API Error: ${err.error?.message || res.status}`);
  }

  const data = await res.json();
  const text = data.choices?.[0]?.message?.content || "";
  return text.trim();
}
