'use client';
import dynamicImport from 'next/dynamic';

// Disable static prerendering — this app requires browser APIs (DOMMatrix, Canvas, IndexedDB)
export const dynamic = 'force-dynamic';

import { Sidebar, MobileMenuButton } from '@/components/layout/sidebar';
import { useUIStore } from '@/stores/ui-store';
import { useClaimStore } from '@/stores/claim-store';
import {
  LayoutDashboard,
  Plus,
  Clock,
  TrendingUp,
  FileCheck,
  Zap,
} from 'lucide-react';

// ─── Dashboard Tab Content ──────────────────────────────
function DashboardContent() {
  const { setNewClaimDialogOpen } = useUIStore();
  const { claimsList } = useClaimStore();

  return (
    <div className="p-6 lg:p-10 max-w-6xl mx-auto font-sans bg-background/50 h-full overflow-y-auto">
      {/* Hero */}
      <div className="mb-10 text-center sm:text-left">
        <h1 className="text-3xl lg:text-4xl font-extrabold text-foreground tracking-tight flex items-center justify-center sm:justify-start gap-2">
          SurveyOS <span className="bg-primary text-primary-foreground px-2 py-0.5 rounded-md text-2xl lg:text-3xl ml-1">V2</span>
        </h1>
        <p className="text-muted-foreground text-sm mt-3 lg:text-base font-medium">
          Motor Insurance Survey Platform — AI-Powered, Offline-First
        </p>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5 mb-10">
        <button
          onClick={() => setNewClaimDialogOpen(true)}
          className="group flex flex-col items-start p-6 rounded-2xl bg-white border border-border shadow-sm hover:shadow-md hover:border-primary/20 hover:-translate-y-0.5 active:scale-[0.98] transition-all duration-300"
        >
          <div className="w-12 h-12 rounded-full bg-primary flex items-center justify-center text-primary-foreground mb-4 shadow-sm group-hover:scale-105 transition-transform">
            <Plus size={24} />
          </div>
          <div className="text-left">
            <div className="text-base font-bold text-foreground">New Claim</div>
            <div className="text-sm text-muted-foreground mt-0.5">Start a comprehensive survey</div>
          </div>
        </button>

        <button className="group flex flex-col items-start p-6 rounded-2xl bg-white border border-border shadow-sm hover:shadow-md hover:border-sidebar-ring/20 hover:-translate-y-0.5 active:scale-[0.98] transition-all duration-300">
          <div className="w-12 h-12 rounded-full bg-secondary flex items-center justify-center text-secondary-foreground mb-4 group-hover:scale-105 transition-transform">
            <FileCheck size={24} />
          </div>
          <div className="text-left">
            <div className="text-base font-bold text-foreground">Open Claim</div>
            <div className="text-sm text-muted-foreground mt-0.5">{claimsList.length} locally saved securely</div>
          </div>
        </button>

        <button className="group flex flex-col items-start p-6 rounded-2xl bg-white border border-border shadow-sm hover:shadow-md hover:border-sidebar-ring/20 hover:-translate-y-0.5 active:scale-[0.98] transition-all duration-300">
          <div className="w-12 h-12 rounded-full bg-secondary flex items-center justify-center text-secondary-foreground mb-4 group-hover:scale-105 transition-transform">
            <Zap size={24} />
          </div>
          <div className="text-left">
            <div className="text-base font-bold text-foreground">Quick Extract</div>
            <div className="text-sm text-muted-foreground mt-0.5">Secure AI document scan</div>
          </div>
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-5 mb-10">
        {[
          { label: 'Claims Today', value: '0', icon: <LayoutDashboard size={18} />, color: 'text-primary' },
          { label: 'This Week', value: '0', icon: <TrendingUp size={18} />, color: 'text-green-600' },
          { label: 'Pending', value: '0', icon: <Clock size={18} />, color: 'text-amber-600' },
          { label: 'Total Claims', value: String(claimsList.length), icon: <FileCheck size={18} />, color: 'text-muted-foreground' },
        ].map((stat) => (
          <div key={stat.label} className="p-5 rounded-2xl bg-white border border-border shadow-sm">
            <div className="flex items-center gap-2 mb-3">
              <span className={stat.color}>{stat.icon}</span>
              <span className="text-[11px] font-bold text-muted-foreground uppercase tracking-widest">{stat.label}</span>
            </div>
            <div className="text-3xl font-extrabold text-foreground tracking-tight">{stat.value}</div>
          </div>
        ))}
      </div>

      {/* Recent Claims */}
      <div className="rounded-2xl bg-white border border-border shadow-sm overflow-hidden mb-8">
        <div className="px-6 py-5 border-b border-border flex items-center justify-between bg-zinc-50/50">
          <h2 className="text-sm font-bold text-foreground uppercase tracking-widest">Recent Claims</h2>
          <span className="text-xs font-semibold px-2 py-0.5 bg-muted rounded-md text-muted-foreground">{claimsList.length} total</span>
        </div>
        {claimsList.length === 0 ? (
          <div className="p-12 text-center flex flex-col items-center">
            <div className="w-16 h-16 rounded-2xl bg-muted flex items-center justify-center mb-4">
              <FileCheck className="text-muted-foreground opacity-50" size={32} />
            </div>
            <div className="text-base font-semibold text-foreground">No claims yet</div>
            <div className="text-sm text-muted-foreground mt-1 max-w-xs mx-auto">
              Click &quot;New Claim&quot; to start drafting your first offline-first survey.
            </div>
          </div>
        ) : (
          <div className="divide-y divide-border">
            {claimsList.slice(0, 10).map((claim) => (
              <div
                key={claim.id}
                className="px-6 py-4 hover:bg-zinc-50/80 cursor-pointer active:bg-zinc-100 transition-colors flex items-center justify-between group"
              >
                <div>
                  <div className="text-sm font-bold text-foreground group-hover:text-primary transition-colors">{claim.label || 'Untitled Claim'}</div>
                  <div className="text-xs text-muted-foreground mt-0.5 font-medium">
                    {new Date(claim.updatedAt).toLocaleDateString(undefined, {
                      year: 'numeric',
                      month: 'short',
                      day: 'numeric',
                    })}
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <span className={`text-[10px] font-bold px-2.5 py-1 rounded-md uppercase tracking-wider ${
                    claim.surveyType === 'spot' ? 'bg-amber-100 text-amber-800 border border-amber-200' :
                    claim.surveyType === 'final' ? 'bg-emerald-100 text-emerald-800 border border-emerald-200' :
                    'bg-secondary text-secondary-foreground border border-border'
                  }`}>
                    {claim.surveyType}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { DetailsTab } from '@/components/tabs/DetailsTab';
import { AssessmentTab } from '@/components/tabs/AssessmentTab';
import { SpotTab } from '@/components/tabs/SpotTab';
import { useAutoSave } from '@/hooks/useAutoSave';
import { NewClaimDialog } from '@/components/dialogs/NewClaimDialog';

// Dynamically import tabs that use browser-only libraries (react-pdf, docx, file-saver)
// ssr:false prevents Turbopack from trying to bundle them on the server
const PhotosTab = dynamicImport(() => import('@/components/tabs/PhotosTab').then(m => ({ default: m.PhotosTab })), { ssr: false });
const ReportTab = dynamicImport(() => import('@/components/tabs/ReportTab').then(m => ({ default: m.ReportTab })), { ssr: false });

// ─── Placeholder for other tabs ─────────────────────────
function TabPlaceholder({ tab }: { tab: string }) {
  if (tab === 'details') return <DetailsTab />;
  if (tab === 'assessment') return <AssessmentTab />;
  if (tab === 'spot') return <SpotTab />;
  if (tab === 'photos') return <PhotosTab />;
  if (tab === 'report') return <ReportTab />;

  return (
    <div className="flex flex-col items-center justify-center h-full min-h-[60vh]">
      <div className="text-center">
        <div className="text-4xl mb-3 opacity-30">🚧</div>
        <div className="text-lg font-semibold text-foreground capitalize">{tab}</div>
        <div className="text-sm text-muted-foreground mt-1">Coming in Phase 5</div>
      </div>
    </div>
  );
}

// ─── Main Page ──────────────────────────────────────────
export default function Home() {
  const { activeTab } = useUIStore();
  
  // Enable offline-first sync (1000ms debounce on keystrokes)
  useAutoSave(1000);

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar />
      <MobileMenuButton />

      <main className="flex-1 overflow-y-auto bg-background">
        {activeTab === 'dashboard' ? <DashboardContent /> : <TabPlaceholder tab={activeTab} />}
      </main>

      {/* Global Modals */}
      <NewClaimDialog />
    </div>
  );
}
